const input = $input.first().json;
let parsed;
if (typeof input.query === 'string') {
  try { parsed = JSON.parse(input.query); } catch (e) { parsed = input; }
} else if (input.query && typeof input.query === 'object') {
  parsed = input.query;
} else {
  parsed = input;
}
return [{ json: parsed }];

const trigger = $('Parse Input').first().json;
const categoryFilter = (trigger.category || '').trim().toLowerCase();
const statusFilter = (trigger.status || '').trim().toLowerCase();
const rows = $input.all();

let filtered = rows;
if (categoryFilter) {
  filtered = filtered.filter(r => (r.json.Category || '').toLowerCase() === categoryFilter);
}
if (statusFilter) {
  filtered = filtered.filter(r => (r.json.Status || '').toLowerCase() === statusFilter);
}

if (filtered.length === 0) {
  return [{ json: { result: 'No formulas found' + (categoryFilter ? ' in category: ' + categoryFilter : '') + (statusFilter ? ' with status: ' + statusFilter : '') + '.' } }];
}

const lines = filtered.map(r => {
  const f = r.json;
  return `[${f.Status}] ${f.Name} | Category: ${f.Category} | pH: ${f.TargetPH || '-'} | Total: ${f.TotalPct || '0'}% | ID: ${f.FormulaID}`;
});

return [{ json: { result: `Found ${filtered.length} formula(s):\n` + lines.join('\n') } }];
